import unittest
from dataclasses import dataclass
from typing import Dict, List, Optional
from decimal import Decimal

# --- Exceptions ---

class InventoryError(Exception):
    """Base class for inventory exceptions."""
    pass

class ProductNotFoundError(InventoryError):
    """Raised when a product ID does not exist in the inventory."""
    pass

class InsufficientStockError(InventoryError):
    """Raised when an operation would result in negative stock."""
    pass

# --- Models ---

@dataclass
class Product:
    """Represents a product in the inventory."""
    name: str
    quantity: int
    price: Decimal

# --- Logic ---

class InventoryManager:
    """Manages product inventory with validation and alerting."""

    def __init__(self, threshold: int = 5):
        self._inventory: Dict[str, Product] = {}
        self.threshold = threshold

    def add_product(self, pid: str, name: str, quantity: int, price: float) -> None:
        """Adds a new product to the inventory."""
        if quantity < 0:
            raise ValueError("Initial quantity cannot be negative.")
        if pid in self._inventory:
            raise InventoryError(f"Product ID '{pid}' already exists.")

        self._inventory[pid] = Product(name, quantity, Decimal(str(price)))

    def update_stock(self, pid: str, delta: int) -> None:
        """Updates stock quantity by a delta (positive or negative)."""
        if pid not in self._inventory:
            raise ProductNotFoundError(f"Product '{pid}' not found.")

        product = self._inventory[pid]
        if product.quantity + delta < 0:
            raise InsufficientStockError(f"Insufficient stock for '{pid}'.")

        product.quantity += delta

    def get_alerts(self) -> List[str]:
        """Returns a list of product IDs that are below the threshold."""
        return [pid for pid, p in self._inventory.items() if p.quantity < self.threshold]

# --- Tests ---

class TestInventoryManager(unittest.TestCase):
    def setUp(self):
        self.manager = InventoryManager(threshold=5)

    def test_add_product(self):
        self.manager.add_product("A1", "Widget", 10, 19.99)
        self.assertEqual(self.manager._inventory["A1"].quantity, 10)

    def test_duplicate_product(self):
        self.manager.add_product("A1", "Widget", 10, 19.99)
        with self.assertRaises(InventoryError):
            self.manager.add_product("A1", "Widget", 5, 10.00)

    def test_update_stock(self):
        self.manager.add_product("A1", "Widget", 10, 19.99)
        self.manager.update_stock("A1", -5)
        self.assertEqual(self.manager._inventory["A1"].quantity, 5)

    def test_insufficient_stock(self):
        self.manager.add_product("A1", "Widget", 2, 19.99)
        with self.assertRaises(InsufficientStockError):
            self.manager.update_stock("A1", -3)

    def test_alerts(self):
        self.manager.add_product("A1", "Low", 2, 10.0)
        self.manager.add_product("A2", "High", 10, 10.0)
        self.assertEqual(self.manager.get_alerts(), ["A1"])

if __name__ == "__main__":
    unittest.main()
